SELECT (YEAR(?startDate) AS ?firstElectionYear) WHERE {
  ?person wdt:P39 wd:Q21971205 ;
          wdt:P551 wd:Q54444 ;
          wdt:P106 ?occupation .
  ?person p:P39 ?positionStatement .
  ?positionStatement ps:P39 wd:Q21971205 .
  ?positionStatement pq:P580 ?startDate .
  ?occupation rdfs:label ?occupationLabel .
  FILTER (LCASE(?occupationLabel) = "slot car business" || LCASE(?occupationLabel) = "slot car")
  FILTER (LANG(?occupationLabel) = "en")
} ORDER BY ASC(?startDate)
LIMIT 1

